column.value:
{
  "pageDescription": "Assay/Test Execution - Comprehensive Bacteriology Testing",
  "sections": {
    "primaryCultureMicroscopy": {
      "title": "A. Primary Culture & Microscopy",
      "gramStaining": {
        "stainType": {"type": "choice", "label": "Stain Type", "options": ["GRAM", "ZN", "MODIFIED_ZN", "INDIA_INK", "KOH", "LACTOPHENOL", "GIEMSA", "ACRIDINE_ORANGE", "CALCOFLUOR", "WET_MOUNT", "OTHER"], "required": true},
        "result": {"type": "choice", "label": "Gram Stain Result", "options": ["GRAM_POS_COCCI_CLUSTERS", "GRAM_POS_COCCI_CHAINS", "GRAM_POS_COCCI_PAIRS", "GRAM_POS_BACILLI", "GRAM_POS_BACILLI_SPORE", "GRAM_NEG_COCCI", "GRAM_NEG_BACILLI", "GRAM_NEG_COCCOBACILLI", "MIXED_FLORA", "NO_ORGANISMS", "YEAST", "YEAST_PSEUDOHYPHAE", "OTHER"], "required": true}
      },
      "microscopyExamination": {
        "wbcCount": {"type": "choice", "label": "WBC Count", "options": ["NONE", "RARE", "FEW", "MODERATE", "MANY", "TNTC"], "required": false},
        "rbcCount": {"type": "choice", "label": "RBC Count", "options": ["NONE", "RARE", "FEW", "MODERATE", "MANY", "TNTC"], "required": false},
        "epithelialCells": {"type": "choice", "label": "Epithelial Cells", "options": ["NONE", "RARE", "FEW", "MODERATE", "MANY", "TNTC"], "required": false},
        "bacteriaObserved": {"type": "choice", "label": "Bacteria Observed", "options": ["NONE", "RARE", "FEW", "MODERATE", "MANY", "TNTC"], "required": false},
        "preliminaryId": {"type": "text", "label": "Preliminary Identification", "required": false}
      }
    },
    "isolationIdentification": {
      "title": "B. Isolation & Identification",
      "cultureIsolation": {
        "mediaUsed": {"type": "multiselect", "label": "Media Used", "options": ["BLOOD_AGAR", "CHOCOLATE_AGAR", "MACCONKEY", "EMB", "XLD", "SS_AGAR", "TCBS", "MANNITOL_SALT", "MUELLER_HINTON", "CLED", "CHROMAGAR", "SABOURAUD", "OTHER"], "required": true},
        "incubationCondition": {"type": "text", "label": "Incubation Condition", "required": false},
        "incubationDuration": {"type": "text", "label": "Incubation Duration", "required": false}
      },
      "colonyReading": {
        "colonyCount": {"type": "text", "label": "Colony Count", "description": "e.g., >10^5 CFU/mL, TNTC", "required": false},
        "colonyMorphology": {"type": "multiselect", "label": "Colony Morphology", "options": ["LARGE", "MEDIUM", "SMALL", "PINPOINT", "MUCOID", "SMOOTH", "ROUGH", "BETA_HEMOLYTIC", "ALPHA_HEMOLYTIC", "GAMMA_HEMOLYTIC", "LACTOSE_FERMENTER", "NON_LACTOSE_FERMENTER", "PIGMENTED", "SWARMING"], "required": false},
        "isolateId": {"type": "text", "label": "Isolate ID", "required": false}
      },
      "biochemicalTests": {
        "catalase": {"type": "choice", "label": "Catalase", "options": ["POSITIVE", "NEGATIVE", "NOT_DONE"], "required": false},
        "coagulase": {"type": "choice", "label": "Coagulase", "options": ["POSITIVE", "NEGATIVE", "NOT_DONE"], "required": false},
        "oxidase": {"type": "choice", "label": "Oxidase", "options": ["POSITIVE", "NEGATIVE", "NOT_DONE"], "required": false},
        "tsiResult": {"type": "choice", "label": "TSI/KIA Result", "options": ["A_A", "K_A", "K_K", "A_A_H2S", "K_A_H2S", "A_A_GAS", "K_A_GAS"], "required": false},
        "motility": {"type": "choice", "label": "Motility", "options": ["POSITIVE", "NEGATIVE", "NOT_DONE"], "required": false},
        "indole": {"type": "choice", "label": "Indole", "options": ["POSITIVE", "NEGATIVE", "NOT_DONE"], "required": false},
        "citrate": {"type": "choice", "label": "Citrate", "options": ["POSITIVE", "NEGATIVE", "NOT_DONE"], "required": false},
        "urease": {"type": "choice", "label": "Urease", "options": ["POSITIVE", "NEGATIVE", "NOT_DONE"], "required": false},
        "lysine": {"type": "choice", "label": "Lysine Decarboxylase", "options": ["POSITIVE", "NEGATIVE", "NOT_DONE"], "required": false},
        "methylRed": {"type": "choice", "label": "Methyl Red", "options": ["POSITIVE", "NEGATIVE", "NOT_DONE"], "required": false},
        "vogesProskauer": {"type": "choice", "label": "Voges-Proskauer", "options": ["POSITIVE", "NEGATIVE", "NOT_DONE"], "required": false},
        "nitrateReduction": {"type": "choice", "label": "Nitrate Reduction", "options": ["POSITIVE", "NEGATIVE", "NOT_DONE"], "required": false},
        "presumptiveId": {"type": "text", "label": "Presumptive Identification", "required": false}
      }
    },
    "drugSusceptibilityTesting": {
      "title": "C. Drug Susceptibility Testing (DST)",
      "dstMethod": {"type": "choice", "label": "DST Method", "options": ["DISC_DIFFUSION", "BROTH_MICRODILUTION", "AST_STRIP", "AUTOMATED_AST"], "required": true, "descriptions": {"DISC_DIFFUSION": "Kirby-Bauer method - measure zone of inhibition", "BROTH_MICRODILUTION": "Determine MIC - quantitative result", "AST_STRIP": "E-test gradient method for MIC determination", "AUTOMATED_AST": "Automated AST systems"}},
      "guidelinesUsed": {"type": "choice", "label": "Interpretation Guidelines", "options": ["CLSI", "EUCAST", "OTHER"], "required": false},
      "antibioticPanel": {"type": "choice", "label": "Antibiotic Panel", "options": ["FIRST_LINE", "SECOND_LINE", "BOTH"], "required": false, "description": "2nd line if resistance detected or clinically indicated. Panel depends on organism and clinical scenario."},
      "antibioticResults": {"type": "array", "label": "Antibiotic Results", "items": {
        "antibiotic": {"type": "text", "label": "Antibiotic"},
        "panelType": {"type": "choice", "label": "Panel", "options": ["1ST_LINE", "2ND_LINE"]},
        "zoneDiameter": {"type": "number", "label": "Zone Diameter (mm)", "description": "For Disc Diffusion method"},
        "mic": {"type": "text", "label": "MIC (µg/mL)", "description": "For Broth Microdilution or AST Strip"},
        "interpretation": {"type": "choice", "label": "Interpretation", "options": ["S", "I", "R"], "description": "Per CLSI/EUCAST guidelines"}
      }}
    },
    "automatedIdentification": {
      "title": "D. Automated Identification and AST",
      "systemType": {"type": "choice", "label": "System Type", "options": ["BD_BACTEC", "VITEK_2", "VITEK_MS", "BD_PHOENIX", "MICROSCAN", "BRUKER_MALDI", "BIOMERIEUX_MALDI", "OTHER"], "required": true},
      "cardType": {"type": "choice", "label": "Card Type", "options": ["GN", "GP", "YST", "ANC", "NH", "AST_GN", "AST_GP", "AST_YS", "OTHER"], "required": false},
      "organismIdentified": {"type": "text", "label": "Organism Identified", "required": true},
      "confidenceScore": {"type": "number", "label": "Confidence Score (%)", "required": false},
      "maldiScore": {"type": "number", "label": "MALDI Score", "description": "Score 2.0+: High confidence, 1.7-1.99: Low confidence, Below 1.7: Not reliable", "required": false}
    },
    "molecularTechniques": {
      "title": "E. Molecular Techniques",
      "nucleicAcidExtraction": {
        "method": {"type": "choice", "label": "Extraction Method", "options": ["MANUAL_COLUMN", "MANUAL_PHENOL", "AUTOMATED_QIAGEN", "AUTOMATED_KINGFISHER", "AUTOMATED_MAGNAPURE", "AUTOMATED_MAXWELL", "CHELEX", "BOILING", "OTHER"], "required": true},
        "nucleicAcidType": {"type": "choice", "label": "Nucleic Acid Type", "options": ["DNA", "RNA", "PLASMID", "CDNA"], "required": true},
        "concentration": {"type": "number", "label": "Concentration (ng/µL)", "required": false},
        "purity260280": {"type": "number", "label": "A260/A280 Ratio", "required": false},
        "purity260230": {"type": "number", "label": "A260/A230 Ratio", "required": false},
        "qualityAssessment": {"type": "choice", "label": "Quality Assessment", "options": ["EXCELLENT", "GOOD", "ACCEPTABLE", "POOR"], "required": false}
      },
      "pcrAssays": {
        "assayType": {"type": "choice", "label": "PCR Assay Type", "options": ["CONVENTIONAL", "REALTIME", "MULTIPLEX", "NESTED", "RT_PCR", "DIGITAL", "LAMP", "OTHER"], "required": true},
        "target": {"type": "choice", "label": "Target Gene/Marker", "options": ["16S_RRNA", "23S_RRNA", "MEC_A", "VAN_A", "VAN_B", "CTX_M", "KPC", "NDM", "OXA_48", "VIM", "IMP", "MCR_1", "TET_M", "ERM_B", "TOX_A", "TOX_B", "SPA", "PVL", "SPECIES_SPECIFIC", "OTHER"], "required": true},
        "result": {"type": "choice", "label": "Result", "options": ["DETECTED", "NOT_DETECTED", "INDETERMINATE", "INVALID"], "required": true},
        "ctValue": {"type": "number", "label": "Ct Value", "description": "For Real-Time PCR", "required": false}
      },
      "wholeGenomeSequencing": {
        "platform": {"type": "choice", "label": "Sequencing Platform", "options": ["ILLUMINA_MISEQ", "ILLUMINA_NEXTSEQ", "ILLUMINA_NOVASEQ", "ONT_MINION", "ONT_GRIDION", "PACBIO_SEQUEL", "ION_TORRENT", "SANGER", "OTHER"], "required": true},
        "analysisType": {"type": "multiselect", "label": "Analysis Type", "options": ["SPECIES_ID", "MLST", "CGMLST", "WGMLST", "AMR_GENES", "VIRULENCE", "PLASMID", "SNP", "PHYLOGENY", "OUTBREAK", "OTHER"], "required": false},
        "coverage": {"type": "number", "label": "Coverage (X)", "required": false},
        "q30Score": {"type": "number", "label": "Q30 Score (%)", "required": false},
        "speciesIdentified": {"type": "text", "label": "Species Identified", "required": false},
        "mlstType": {"type": "text", "label": "MLST Type", "required": false},
        "amrGenes": {"type": "text", "label": "AMR Genes Detected", "required": false},
        "virulenceFactors": {"type": "text", "label": "Virulence Factors", "required": false}
      }
    }
  }
}
